    @Test
    void mapActDiagnosisID10_two_rows() throws IOException {
        String csvRow1 = "\\ACT Diagnosis ICD-10\\A00-B99 Certain infectious and parasitic diseases (A00-B99)\\,56,0,true,B20-B20 Human immunodeficiency virus [HIV] disease (B20),null,null,46449845,46450871,1,1";
        String csvRow2 = "\\ACT Procedures CPT\\Pathology and Laboratory Procedures\\Organ or Disease Oriented Panels\\,433,0,true,\"Comprehensive metabolic panel This panel must include the following: Albumin (82040) Bilirubin, total (82247) Calcium, total (82310) Carbon dioxide (bicarbonate) (82374) Chloride (82435) Creatinine (82565) Glucose (82947) Phosphatase, alkaline (84075) Potassium (84132) Protein, total (84155) Sodium (84295) Transferase, alanine amino (ALT) (SGPT) (84460) Transferase, aspartate amino (AST) (SGOT) (84450) Urea nitrogen (BUN) (84520)\",null,null,1640676907,1640679697,4,1";
        ColumnMeta columnMeta1 = columnMetaMapper.mapCSVRowToColumnMeta(csvParser.parseLine(csvRow1));
        ColumnMeta columnMeta2 = columnMetaMapper.mapCSVRowToColumnMeta(csvParser.parseLine(csvRow2));
        assertNotNull(columnMeta1);
        assertNotNull(columnMeta2);
        assertEquals("\\ACT Diagnosis ICD-10\\A00-B99 Certain infectious and parasitic diseases (A00-B99)\\", columnMeta1.name());
        assertEquals("\\ACT Procedures CPT\\Pathology and Laboratory Procedures\\Organ or Disease Oriented Panels\\", columnMeta2.name());
        assertEquals(List.of("B20-B20 Human immunodeficiency virus [HIV] disease (B20)"), columnMeta1.categoryValues());
        assertEquals(List.of("Comprehensive metabolic panel This panel must include the following: Albumin (82040) Bilirubin, total (82247) Calcium, total (82310) Carbon dioxide (bicarbonate) (82374) Chloride (82435) Creatinine (82565) Glucose (82947) Phosphatase, alkaline (84075) Potassium (84132) Protein, total (84155) Sodium (84295) Transferase, alanine amino (ALT) (SGPT) (84460) Transferase, aspartate amino (AST) (SGOT) (84450) Urea nitrogen (BUN) (84520)"), columnMeta2.categoryValues());
    }

