    @Test
    void shouldCorrectlyParseConceptPath_With_SameNumericValueExistingInLastNodes() throws IOException {
        ColumnMeta columnMeta = this.columnMetaMapper.mapCSVRowToColumnMeta(csvParser.parseLine("\\laboratory\\bacterial infection\\Cefazolin 1\\1\\,1,0,true,1,null,null,169744665,169746284,19,19"));
        assertEquals("\\laboratory\\bacterial infection\\Cefazolin 1\\", columnMeta.name());
    }

    @Test
    void shouldParseGenomicConceptPath_ofLengthTwo() throws IOException {
        ColumnMeta columnMeta = this.columnMetaMapper.mapCSVRowToColumnMeta(csvParser.parseLine("\\open_access-1000Genomes\\GENOMES ON GRCH381000\\,5,0,true,FALSE,null,null,1569879,1735060,4978,4978"));
        assertEquals("\\open_access-1000Genomes\\GENOMES ON GRCH381000\\", columnMeta.name());
    }

